import{_ as o,o as a,c as t,a3 as c}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Module extract:ast","description":"模块 extract:ast 负责基于 Clang AST 的符号提取，是 C++ 项目解析流水线的核心引擎。它通过自定义的递归 AST 访问器（SymbolExtractorVisitor）和消费者（SymbolExtractorConsumer）来遍历翻译单元，为每个可提取的声明计算唯一标识、源片段边界、词法上下文、文档注释和函数签名，同时收集各类关系（函数调用、成员访问、引用、继承）以及文件依赖。提取结果以 ASTResult 结构体封装，包含符号列表、关系列表和依赖文件集合，而模块唯一的公开入口点为 extract_symbols 函数。","frontmatter":{"title":"Module extract:ast","description":"模块 extract:ast 负责基于 Clang AST 的符号提取，是 C++ 项目解析流水线的核心引擎。它通过自定义的递归 AST 访问器（SymbolExtractorVisitor）和消费者（SymbolExtractorConsumer）来遍历翻译单元，为每个可提取的声明计算唯一标识、源片段边界、词法上下文、文档注释和函数签名，同时收集各类关系（函数调用、成员访问、引用、继承）以及文件依赖。提取结果以 ASTResult 结构体封装，包含符号列表、关系列表和依赖文件集合，而模块唯一的公开入口点为 extract_symbols 函数。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/ast.md","filePath":"zh/clore/modules/extract/ast.md"}'),r={name:"zh/clore/modules/extract/ast.md"};function d(l,e,i,s,n,u){return a(),t("div",null,[...e[0]||(e[0]=[c("",61)])])}const p=o(r,[["render",d]]);export{m as __pageData,p as default};
